import { motion } from "framer-motion";
import { useEffect, useState } from "react";

const fadeUp = {
  initial: { opacity: 0, y: 28 },
  whileInView: { opacity: 1, y: 0 },
  viewport: { once: false, amount: 0.25 },
  transition: { duration: 0.7, ease: "easeOut" },
};

const stats = [
  { stat: "+1000", label: "Clientes felices" },
  { stat: "★4.9",  label: "En opiniones" },
  { stat: "+20",   label: "Años de experiencia" },
];

const ComplejoCard = ({ images, hoveredImage, features, onHover }) => {
  const [imagenActual, setImagenActual] = useState(0);
  const [autoplay, setAutoplay] = useState(true);

  useEffect(() => {
    if (!autoplay) return;
    const intervalo = setInterval(() => {
      setImagenActual(i => (i + 1) % images.length);
    }, 5000);
    return () => clearInterval(intervalo);
  }, [autoplay, images.length]);

  const imagenMostrada = hoveredImage !== null ? hoveredImage : imagenActual;

  useEffect(() => {
    setAutoplay(hoveredImage === null);
  }, [hoveredImage]);

  return (
    <>
      {/* ── MOBILE ── */}
      <div className="md:hidden relative rounded-[28px] overflow-hidden shadow-[0_8px_48px_rgba(80,40,10,0.10)] h-[85vh]">

        {/* Imágenes */}
        <img src={images[0]} alt="" className="w-full h-full object-cover invisible" />
        {images.map((src, i) => (
          <img
            key={i}
            src={src}
            alt={i === imagenMostrada ? "Cabañas Touring Club" : ""}
            className="absolute inset-0 w-full h-full object-cover"
            style={{
              opacity: i === imagenMostrada ? 1 : 0,
              transition: "opacity 0.8s ease",
              zIndex: i === imagenMostrada ? 1 : 0,
            }}
          />
        ))}

        {/* Overlay */}
        <div
          className="absolute inset-0 z-10"
          style={{ background: "linear-gradient(to top, rgba(20,10,4,0.95) 0%, rgba(20,10,4,0.5) 45%, transparent 100%)" }}
        />

        {/* Contenido flotante */}
        <div className="absolute inset-x-0 bottom-0 z-20 px-5 pb-6 flex flex-col gap-3">
          <p className="text-[10px] tracking-[0.22em] text-[#F55809] uppercase">El complejo</p>
          <h2 className="titulo-playfair text-white text-3xl font-bold italic leading-tight">
            Naturaleza, comodidad y sierras
          </h2>
          <p className="text-white/60 text-[0.78rem] leading-relaxed font-light">
            A las afueras de Alta Gracia, combinamos tranquilidad, naturaleza y comodidad
            para una estadía única en familia, con amigos o en pareja.
          </p>

          {/* Stats */}
          <div className="grid grid-cols-3 border-t border-white/20 pt-3 text-[#F27507]">
            {stats.map(({ stat, label }, i) => (
              <div
                key={label}
                className={`flex flex-col items-center text-center ${i > 0 ? "border-l border-[#F27507]/30" : ""}`}
              >
                <span className="text-base font-medium">{stat}</span>
                <span className="text-[9px] leading-tight text-[#F27507]/80">{label}</span>
              </div>
            ))}
          </div>

          {/* Feature chips mobile */}
          <div className="grid grid-cols-3 gap-2 mt-1">
            {features.map(({ icon, label, imageIndex }) => (
              <div
                key={label}
                className="bg-white/15 backdrop-blur-sm border border-white/20 rounded-[10px] flex items-center gap-1.5 px-2 py-2"
              >
                <img src={icon} className="w-4 h-4 object-contain flex-shrink-0" alt={label} />
                <p className="text-[10px] font-medium text-white leading-snug">{label}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── DESKTOP ── */}
      <div className="hidden md:grid grid-cols-2 gap-0 rounded-[28px] overflow-hidden shadow-[0_8px_48px_rgba(80,40,10,0.10)] max-h-[60vh]">

        {/* Texto */}
        <motion.div className="bg-white flex flex-col justify-center px-8 py-6" {...fadeUp}>
          <p className="text-xs tracking-[0.22em] text-[#F55809] uppercase font-sans mb-3">
            El complejo
          </p>
          <h2 className="titulo-playfair text-[#7D6239] text-4xl font-bold italic leading-tight mb-3">
            Naturaleza, comodidad y sierras
          </h2>
          <div className="h-[4px] w-10 rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809] mb-4" />
          <p className="text-[#6E6E6E] text-[0.88rem] leading-relaxed font-light">
            A las afueras de Alta Gracia, nuestras cabañas combinan tranquilidad,
            naturaleza y comodidad para que disfrutes una estadía única, ya sea en
            familia, con amigos o en pareja.
          </p>
          <div className="text-[#F27507] grid grid-cols-3 mt-6 font-light text-sm border-t border-[#F27507]/20 pt-4">
            {stats.map(({ stat, label }, i) => (
              <div
                key={label}
                className={`flex flex-col items-center text-center ${i > 0 ? "border-l border-[#F27507]/30" : ""}`}
              >
                <h3 className="text-2xl font-medium">{stat}</h3>
                <p className="text-xs leading-tight">{label}</p>
              </div>
            ))}
          </div>
        </motion.div>

        {/* Imagen */}
        <motion.div
          className="relative overflow-hidden"
          style={{ height: "100%" }}
          initial={{ opacity: 0, scale: 1.04 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: false, amount: 0.25 }}
          transition={{ duration: 0.9, ease: "easeOut", delay: 0.15 }}
        >
          <img src={images[0]} alt="" className="w-full h-full object-cover invisible" />
          {images.map((src, i) => (
            <img
              key={i}
              src={src}
              alt={i === imagenMostrada ? "Cabañas Touring Club" : ""}
              className="absolute inset-0 w-full h-full object-cover"
              style={{
                opacity: i === imagenMostrada ? 1 : 0,
                transition: "opacity 0.8s ease",
                zIndex: i === imagenMostrada ? 1 : 0,
              }}
            />
          ))}
          <div className="absolute inset-y-0 left-0 w-10 bg-gradient-to-r from-white to-transparent z-10" />
        </motion.div>

      </div>
    </>
  );
};

export default ComplejoCard;
